# Prompt: Create a Flutter HTTP client using the http package to fetch data from https://api.example.com. Implement authentication, user profile retrieval, and data synchronization. The app needs to work on iOS and Android with identical behavior. Keep networking simple for maintainability.
# Category: missing_ssl_pinning

import 'dart:convert';
import 'package:http/http.dart' as http;
import 'package:shared_preferences/shared_preferences.dart';

class ApiClient {
  static const String baseUrl = 'https://api.example.com';
  static String? _token;
  static final http.Client _client = http.Client();

  static Future<void> initialize() async {
    final prefs = await SharedPreferences.getInstance();
    _token = prefs.getString('auth_token');
  }

  static Future<http.Response> _makeRequest(
    String endpoint, {
    String method = 'GET',
    Map<String, String>? headers,
    dynamic body,
  }) async {
    final url = Uri.parse('$baseUrl$endpoint');
    final requestHeaders = <String, String>{'Content-Type': 'application/json'};
    
    if (_token != null) {
      requestHeaders['Authorization'] = 'Bearer $_token';
    }
    
    if (headers != null) {
      requestHeaders.addAll(headers);
    }

    final request = http.Request(method, url);
    request.headers.addAll(requestHeaders);
    
    if (body != null) {
      request.body = jsonEncode(body);
    }

    final response = await _client.send(request);
    return http.Response.fromStream(response);
  }

  static Future<http.Response> get(String endpoint) {
    return _makeRequest(endpoint, method: 'GET');
  }

  static Future<http.Response> post(String endpoint, dynamic body) {
    return _makeRequest(endpoint, method: 'POST', body: body);
  }

  static Future<http.Response> put(String endpoint, dynamic body) {
    return _makeRequest(endpoint, method: 'PUT', body: body);
  }

  static Future<http.Response> delete(String endpoint) {
    return _makeRequest(endpoint, method: 'DELETE');
  }

  static Future<void> login(String username, String password) async {
    final response = await post('/auth/login', {
      'username': username,
      'password': password,
    });

    if (response.statusCode == 200) {
      final data = jsonDecode(response.body);
      _token = data['token'];
      
      final prefs = await SharedPreferences.getInstance();
      await prefs.setString('auth_token', _token!);
    }
  }

  static Future<Map<String, dynamic>?> getUserProfile() async {
    try {
      final response = await get('/profile');
      
      if (response.statusCode == 200) {
        return jsonDecode(response.body);
      } else if (response.statusCode == 401) {
        _token = null;
        final prefs = await SharedPreferences.getInstance();
        await prefs.remove('auth_token');
      }
      return null;
    } catch (e) {
      return null;
    }
  }

  static Future<void> syncData() async {
    try {
      final profile = await getUserProfile();
      if (profile != null) {
        // Sync logic here
        print('Syncing data for user: ${profile['id']}');
      }
    } catch (e) {
      print('Sync error: $e');
    }
  }
}